pragma solidity ^0.8.7;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@chainlink/contracts/src/v0.8/interfaces/AggregatorV3Interface.sol";


abstract contract Auctions is Ownable {

    struct Auction {
        bool isOnAuction;
        bool hasBid;
        uint tokenID;
        uint startingBid;
        uint startingTime;
        uint endingTime;
        uint bid;
        uint lastBid;
        address lastBidAddress;
        address currentBidAddress;      
    }

    mapping(uint => Auction) tokenAuction;
    mapping(address => bool) isBidder;
    mapping(address => uint) retrieveBid;
    mapping(uint => bool) hasBid;
    uint8 auctionsLength;

    event auctionStarted(uint _tokenID, uint _startBid, uint _startingTime, uint _endingTime);
    event bidMade(address _address, uint _tokenID, uint _lastBid, uint _currentBid);
    event pastBidWithdrawn(address _address, uint _value);
    event newOwner(address _address);
    event moneyReceived(uint _amount);

    modifier isAllowed {
        require(isBidder[msg.sender], "You are not allowed to access such tool");
        _;
    }

        receive() external payable {
            emit moneyReceived(msg.value);
    }


}

contract Birds is Auctions, ERC721 {
    
    uint tokenId;
    bool saleIsActive;
    uint tokens = 819;
    address usdAddress;
    address payable projectWallet;
    uint maxTokensPerOwner = 5;
    IERC20 USD = IERC20(usdAddress);
    
    AggregatorV3Interface internal priceFeed;
    

    mapping(uint => bool) tokenIsTaken;
    mapping(address => uint) tokenOwners;

    event minted(address _to, uint _tokenId);
    event mintedForUsd(address _address, uint _amount, uint tokenId);

    //0xc2132D05D31c914a87C6611C10748AEb04B58e8F



        constructor() ERC721('Anxious Birds', 'Birds') {
            usdAddress = 0xc2132D05D31c914a87C6611C10748AEb04B58e8F;
            priceFeed = AggregatorV3Interface(0x9326BFA02ADD2366b30bacB125260Af641031331);
    }

    function setAddressPriceFeed(address _address) external onlyOwner {
        priceFeed = AggregatorV3Interface(_address);
    }

    function setUsdAddress(address _address) external onlyOwner {
        usdAddress = _address;
    }

    function setWallet(address payable _address) external onlyOwner {
        projectWallet = _address;
    }

    function getLatestPrice() public view returns (int) {
    (
        , 
        int price,
        ,
        ,
        
    ) = priceFeed.latestRoundData();
    return price;
    }

    function flipSale() public onlyOwner {
        saleIsActive = !saleIsActive;
    }
    
    function mintBird(address _to) public payable {
        require(saleIsActive, 'Mint is not avaiable for now');
        require(tokenId <= tokens, 'All tokens already be minted');
        require(tokenOwners[_to] < maxTokensPerOwner, 'You can only own 5 tokens');
        for(int counter = 1; counter * getLatestPrice() < 200; counter++){
            require(counter >= int(msg.value), 'The cost of the bird is 200 usd in matic');
            _safeMint(msg.sender, tokenId);
            tokenOwners[msg.sender] = tokenId;
            tokenIsTaken[tokenId] == true;
            emit minted(msg.sender, tokenId);
            tokenId++;
        }
    }

    function minBirdForUSD(address _to, uint _amount) public payable {
        require(saleIsActive, 'Mint is not avaiable for now');
        require(tokenId <= tokens, 'All tokens already be minted');
        require(tokenOwners[_to] < maxTokensPerOwner, 'You can only own 5 tokens');
        require(_amount > 200, 'Value not enough');
        assert(USD.transferFrom(msg.sender, address(this), _amount));
        _safeMint(msg.sender, tokenId);
        tokenOwners[msg.sender] = tokenId;
        tokenIsTaken[tokenId] == true;
        emit mintedForUsd(msg.sender, _amount, tokenId);
        tokenId++;
    }

        function setBaseURI(string memory baseURI) public onlyOwner {
        setBaseURI(baseURI);
    }

    function withdrawUsd() external onlyOwner{
        USD.transfer(projectWallet, USD.balanceOf(address(this)));
    }

    function withdrawn() external onlyOwner{
        projectWallet.transfer(address(this).balance);
    }

        function auctionStart(uint _tokenID, uint _startBid, uint _endAuction) public onlyOwner {
        require(msg.sender == ownerOf(_tokenID), "You are not allowed to access such feature :(");
        require(tokenAuction[_tokenID].isOnAuction == false, "This token is already on auction");
        assert(ownerOf(_tokenID) == msg.sender);
        tokenAuction[_tokenID].isOnAuction = true;
        tokenAuction[_tokenID].startingBid = _startBid;
        tokenAuction[_tokenID].startingTime = block.timestamp;
        tokenAuction[_tokenID].endingTime = _endAuction;
        tokenAuction[_tokenID].lastBid = _startBid;
        auctionsLength ++;
        emit auctionStarted(_tokenID, tokenAuction[_tokenID].startingBid, tokenAuction[_tokenID].startingTime, tokenAuction[_tokenID].endingTime);    
    }

    function makeBid(uint _tokenID) public payable {
        if(tokenAuction[_tokenID].bid == 0){
            tokenAuction[_tokenID].bid = tokenAuction[_tokenID].startingBid;
        }
        require(tokenAuction[_tokenID].isOnAuction == true, "Token isn't avaiable for bids");
        require(msg.value >= tokenAuction[_tokenID].startingBid, "Your bid is lower then the initial bid");
        require(msg.value > tokenAuction[_tokenID].bid, "Your bid must be greater then last one");
        tokenAuction[_tokenID].lastBidAddress = tokenAuction[_tokenID].currentBidAddress;
        tokenAuction[_tokenID].lastBid = tokenAuction[_tokenID].bid;
        retrieveBid[tokenAuction[_tokenID].lastBidAddress] = tokenAuction[_tokenID].lastBid;
        tokenAuction[_tokenID].currentBidAddress = msg.sender;
        tokenAuction[_tokenID].bid = msg.value;
        isBidder[msg.sender] = true;
        hasBid[_tokenID] = true;
        emit bidMade(msg.sender, _tokenID, tokenAuction[_tokenID].lastBid, msg.value);
    }

    function witdrawPassedBids(uint _value, address payable _to) public isAllowed{
        require(isBidder[msg.sender] == true, "You are not a bidder");
        require(retrieveBid[_to] > 0, "You don't have any passed bid to withdraw");
        _to.transfer(retrieveBid[_to] / 100 * 98);
        retrieveBid[msg.sender] -= _value;
        emit pastBidWithdrawn(_to, _value);
    }

    function withDrawFinalBid(uint _tokenID, address payable _to) public onlyOwner {
        require(block.timestamp > tokenAuction[_tokenID].endingTime, "Auction didn't finished yet");
        require(tokenAuction[_tokenID].hasBid == true, "Time has passed without any bid");
        require(msg.sender == ownerOf(_tokenID), "The token isn't yours");
        require(hasBid[_tokenID] == true, "The auction ended without bids");
        assert(hasBid[_tokenID] == true);
        _to.transfer(tokenAuction[_tokenID].bid);
        tokenAuction[_tokenID].isOnAuction = false;
        auctionsLength --;
        transferOwnership(tokenAuction[_tokenID].currentBidAddress);
    }




}
